:root {
  /* PBSK-All Games-Magenta Theme-v1 */
  --pbsk-theme-status: LIVE;
  --pbsk-theme-bodyTextColor: #ffffff;
  --pbsk-theme-bodyTextColor-rgb: 255 255 255;
  --pbsk-theme-bodyBackgroundColor: #e4276a;
  --pbsk-theme-bodyBackgroundColor-rgb: 228 39 106;
  --pbsk-theme-accentBackgroundColor: rgb(0 0 0 / 0);
  --pbsk-theme-backgroundImage: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
  --pbsk-theme-backgroundPattern: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
  --pbsk-theme-featureBackgroundColor: #ffffff;
  --pbsk-theme-featureBackgroundColor-rgb: 255 255 255;
  --pbsk-theme-featureHighlightColor: #2538c4;
  --pbsk-theme-featureHighlightColor-rgb: 37 56 196;
  --pbsk-theme-calloutTextColor: #bc0159;
  --pbsk-theme-calloutTextColor-rgb: 188 1 89;
  --pbsk-theme-calloutBackgroundColor: #f7e03b;
  --pbsk-theme-calloutBackgroundColor-rgb: 247 224 59;
  --pbsk-theme-badgeTextColor: #ffffff;
  --pbsk-theme-badgeTextColor-rgb: 255 255 255;
  --pbsk-theme-badgeBackgroundColor: #08ab4e;
  --pbsk-theme-badgeBackgroundColor-rgb: 8 171 78;
  --pbsk-theme-navBackgroundColor: rgb(0 0 0 / 0);
  --pbsk-theme-uiControlColor: #131d8c;
  --pbsk-theme-uiControlColor-rgb: 19 29 140;
  --pbsk-theme-uiLabelColor: #ffffff;
  --pbsk-theme-uiLabelColor-rgb: 255 255 255;
  --pbsk-theme-uiHighlightColor: #ffffff;
  --pbsk-theme-uiHighlightColor-rgb: 255 255 255;
}


[data-theme-context='masthead'] {
  /* XRID-Xavier Riddle and the Secret Museum-Portal Theme-v2 */
  --pbsk-theme-status: LIVE;
  --pbsk-theme-bodyTextColor: #000000;
  --pbsk-theme-bodyTextColor-rgb: 0 0 0;
  --pbsk-theme-bodyBackgroundColor: #16e4d8;
  --pbsk-theme-bodyBackgroundColor-rgb: 22 228 216;
  --pbsk-theme-accentBackgroundColor: rgb(0 0 0 / 0);
  --pbsk-theme-backgroundImage-aspectRatio: 4.124378109452737;
  --pbsk-theme-backgroundImage-width: 3316px;
  --pbsk-theme-backgroundImage-height: 804px;
  --pbsk-theme-backgroundPattern: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
  --pbsk-theme-featureBackgroundColor: #ffffff;
  --pbsk-theme-featureBackgroundColor-rgb: 255 255 255;
  --pbsk-theme-featureHighlightColor: #772080;
  --pbsk-theme-featureHighlightColor-rgb: 119 32 128;
  --pbsk-theme-calloutTextColor: #ffffff;
  --pbsk-theme-calloutTextColor-rgb: 255 255 255;
  --pbsk-theme-calloutBackgroundColor: #0d810c;
  --pbsk-theme-calloutBackgroundColor-rgb: 13 129 12;
  --pbsk-theme-badgeTextColor: #ffffff;
  --pbsk-theme-badgeTextColor-rgb: 255 255 255;
  --pbsk-theme-badgeBackgroundColor: #8534a4;
  --pbsk-theme-badgeBackgroundColor-rgb: 133 52 164;
  --pbsk-theme-navBackgroundColor: #16e4d8;
  --pbsk-theme-navBackgroundColor-rgb: 22 228 216;
  --pbsk-theme-uiControlColor: #8534a4;
  --pbsk-theme-uiControlColor-rgb: 133 52 164;
  --pbsk-theme-uiLabelColor: #ffffff;
  --pbsk-theme-uiLabelColor-rgb: 255 255 255;
  --pbsk-theme-uiHighlightColor: #772080;
  --pbsk-theme-uiHighlightColor-rgb: 119 32 128;
}

[data-theme-context='masthead'] {
  --pbsk-theme-backgroundImage: image-set(
    url('/pbs-assets/cms-assets.prod.pbskids.org/global/Property-Assets/XRID-Xavier-Riddle/Backgrounds/XRID-background-portal2-v1.jpg') 1x,
